export default "__VITE_ASSET__DdUQSBBl__"
<template>
  <Transition name="preloader">
    <div v-if="isVisible" class="preloader">
      <div class="preloader__content">
        <!-- Logo -->
        <div class="preloader__logo">
          <div class="logo">
            <img
              src="../assets/logo/bl-logo-bianco.svg"
              alt="Logo bianco di BL Service"
            />
          </div>
        </div>

        <!-- Progress bar -->
        <div class="preloader__progress">
          <div
            class="preloader__progress-bar"
            :style="{ width: `${progress}%` }"
          ></div>
        </div>
      </div>
    </div>
  </Transition>
</template>

<script setup>
const props = defineProps({
  duration: {
    type: Number,
    default: 2500,
  },
});

const emit = defineEmits(["complete"]);

const isVisible = ref(true);
const progress = ref(0);
const colors = ["#d4a853", "#c47369", "#8a9bae", "#0066cc"];

onMounted(() => {
  const startTime = Date.now();

  const updateProgress = () => {
    const elapsed = Date.now() - startTime;
    progress.value = Math.min((elapsed / props.duration) * 100, 100);

    if (elapsed < props.duration) {
      requestAnimationFrame(updateProgress);
    } else {
      setTimeout(() => {
        isVisible.value = false;
        setTimeout(() => {
          emit("complete");
        }, 800);
      }, 200);
    }
  };

  requestAnimationFrame(updateProgress);
});
</script>

<style lang="scss" scoped>
.preloader {
  position: fixed;
  inset: 0;
  z-index: $z-preloader;
  background: $color-dark;
  @include flex-center;
  flex-direction: column;

  &__content {
    @include flex-center;
    flex-direction: column;
    gap: $spacing-3xl;
  }

  &__logo {
    @include flex-center;
    gap: $spacing-lg;

    img {
      width: 100%;
    }
  }

  &__progress {
    width: 200px;
    height: 2px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 1px;
    overflow: hidden;
  }

  &__progress-bar {
    height: 100%;
    background: linear-gradient(
      90deg,
      $color-gold,
      $color-copper,
      $color-gray,
      $color-blue
    );
    transition: width 0.1s linear;
  }
}

@keyframes circleAppear {
  to {
    opacity: 1;
    transform: scale(1) rotate(0deg);
  }
}

@keyframes circleRotate {
  to {
    transform: rotate(360deg);
  }
}

@keyframes textAppear {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

// Slide out to right
.preloader-leave-active {
  transition: transform 0.8s cubic-bezier(0.7, 0, 0.3, 1);
}

.preloader-leave-to {
  transform: translateX(100%);
}
</style>
export default "__VITE_ASSET__DhEZJBRo__"
<template>
  <!-- Header contenuto nella metà sinistra -->
  <header
    :id="headerId"
    class="header"
    :class="{ 'is-visible': isVisible, 'is-scrolled': isScrolled }"
  >
    <div class="header__container">
      <!-- Logo -->
      <a href="#" class="header__logo" @click.prevent="handleNavigate('/')">
        <div class="logo">
          <img src="../assets/logo/LogoColore2.svg" alt="Logo di BL Service" />
        </div>
      </a>

      <!-- Menu Toggle -->
      <!-- Mobile (Block style - solo ≤575px) -->
      <!-- <button
        class="header__menu-btn header__menu-btn--mobile"
        :class="{ 'is-active': isMenuOpen }"
        @click="toggleMenu"
        aria-label="Menu"
      >
        <span class="header__menu-label">
          <span
            class="header__menu-label-text header__menu-label-text--menu uppercase"
            >menu</span
          >
          <span
            class="header__menu-label-text header__menu-label-text--close uppercase"
            >chiudi</span
          >
        </span>
        <span class="header__menu-icon">
          <span class="header__menu-line"></span>
          <span class="header__menu-line"></span>
          <span class="header__menu-line"></span>
        </span>
      </button> -->

      <!-- Desktop (Flex style - solo >575px) -->
      <!-- <button
        class="header__menu-btn header__menu-btn--desktop"
        :class="{ 'is-active': isMenuOpen }"
        @click="toggleMenu"
        aria-label="Menu"
      >
        <span class="header__menu-label">
          <span
            class="header__menu-label-text header__menu-label-text--menu uppercase"
            >menu</span
          >
          <span
            class="header__menu-label-text header__menu-label-text--close uppercase"
            >chiudi</span
          >
        </span>
        <span class="header__menu-icon">
          <span class="header__menu-line"></span>
          <span class="header__menu-line"></span>
          <span class="header__menu-line"></span>
        </span>
      </button> -->
    </div>
  </header>

  <!-- Menu Overlay (class-based, sempre nel DOM per animazioni scaleX) -->
  <Teleport to="body">
    <div
      class="menu-overlay"
      :class="{ 'is-active': isMenuOpen, 'is-closing': isClosing }"
    >
      <!-- Reveal panel sinistro (grigio, scaleX da sinistra) -->
      <div class="menu-overlay__reveal" @click="closeMenu"></div>

      <!-- Blur backdrop (SOPRA il reveal) -->
      <div class="menu-overlay__blur-backdrop" @click="closeMenu"></div>

      <!-- Pannello destro (bianco, scaleX da destra) -->
      <nav class="menu-overlay__panel">
        <!-- Header con linea e sottotitolo -->
        <div class="menu-overlay__header">
          <span class="menu-overlay__line"></span>
          <span class="menu-overlay__subtitle"
            >BL SERVICE - Lavorazioni meccaniche</span
          >
        </div>

        <!-- Menu items -->
        <ul class="menu-overlay__list">
          <li
            v-for="(item, index) in menuItems"
            :key="item.path"
            class="menu-overlay__item"
            :style="{
              transitionDelay: isMenuOpen
                ? `${0.6 + index * 0.06}s`
                : `${(menuItems.length - 1 - index) * 0.04}s`,
            }"
          >
            <a
              href="#"
              class="menu-overlay__link"
              :class="{ 'is-featured': item.featured }"
              @click.prevent="handleNavigate(item.path)"
            >
              {{ item.label }}
            </a>
          </li>
        </ul>
      </nav>
    </div>
  </Teleport>
</template>

<script setup lang="ts">
const route = useRoute();
const headerId = computed(() => `header-${route.name || "default"}`);

const isVisible = ref(false);
const isScrolled = ref(false);
const isMenuOpen = ref(false);
const isClosing = ref(false);
const { navigateWithTransition } = usePageTransition();

const menuItems = [
  { label: "Lavorazioni", path: "/lavorazioni" },
  { label: "BL Service", path: "/bl-service", featured: true },
  { label: "Servizi", path: "/servizi" },
  { label: "Contatti", path: "/contatti" },
];

const toggleMenu = () => {
  if (isMenuOpen.value) {
    // Chiusura: attiva is-closing
    isClosing.value = true;
    // Rimuovi is-active dopo un frame per far partire la transition
    requestAnimationFrame(() => {
      isMenuOpen.value = false;
    });
    // Rimuovi is-closing dopo l'animazione completa (blur delay 1.1s + duration 0.6s = 1.7s)
    setTimeout(() => {
      isClosing.value = false;
      document.body.style.overflow = "";
    }, 1800);
  } else {
    // Apertura normale
    isMenuOpen.value = true;
    isClosing.value = false;
    document.body.style.overflow = "hidden";
  }
};

const closeMenu = () => {
  if (isMenuOpen.value) {
    isClosing.value = true;
    requestAnimationFrame(() => {
      isMenuOpen.value = false;
    });
    setTimeout(() => {
      isClosing.value = false;
      document.body.style.overflow = "";
    }, 1800);
  }
};

const handleNavigate = (path: string) => {
  closeMenu();
  navigateWithTransition(path);
};

const showHeader = () => {
  isVisible.value = true;
};

const handleScroll = () => {
  isScrolled.value = window.scrollY > 50;
};

defineExpose({ showHeader });

onMounted(() => {
  window.addEventListener("scroll", handleScroll);
});

onUnmounted(() => {
  window.removeEventListener("scroll", handleScroll);
});
</script>

<style lang="scss" scoped>
.header {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: $z-header;
  padding: $spacing-md;
  transition:
    // background $transition-base,
    background 0.4s cubic-bezier(0.4, 0, 0.2, 1),
    padding $transition-base;

  &.is-scrolled {
    background: rgb(255, 255, 255);
    backdrop-filter: blur(10px);

    @media (max-width: 575px) {
      .header__container {
        width: 65%;
        margin: 0 auto;
      }
    }
  }

  &__container {
    width: 100%;
    transition: width 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  }

  // Staggered entrance
  .header__logo,
  .header__menu-btn {
    opacity: 0;
    transform: translateY(-20px);
    transition:
      opacity 0.6s ease,
      transform 0.6s ease;
  }

  .header__logo .logo {
    width: 55%;
    margin: 0 auto;

    img {
      width: 100%;

      @media (min-width: $breakpoint-md) {
        width: 85%;
      }
    }
  }

  &.is-visible {
    .header__logo {
      opacity: 1;
      transform: translateY(0);
      transition-delay: 0s;
    }

    .header__menu-btn {
      width: 100%;
      opacity: 1;
      transform: translateY(0);
      transition-delay: 0.15s;
    }
  }

  &__menu-btn {
    position: relative;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0;

    &--mobile {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: $spacing-sm;
      margin-top: 1.5rem;

      @media (min-width: 769px) {
        display: none;
      }

      // Label container
      .header__menu-label {
        position: relative;
        width: auto;
        height: auto;
        flex-shrink: 0;
      }

      // Testo MENU / CHIUDI (orizzontale)
      .header__menu-label-text {
        position: absolute;
        top: 0;
        left: 50%;
        transform: translateX(-50%);
        font-size: $font-size-xs;
        font-weight: $font-weight-medium;
        letter-spacing: 0.1em;
        writing-mode: horizontal-tb;
        white-space: nowrap;

        &--menu {
          opacity: 1;
          visibility: visible;
          transition:
            opacity 0.3s ease 0.15s,
            visibility 0s linear 0.15s,
            transform 0.3s ease 0.15s;
        }

        &--close {
          opacity: 0;
          visibility: hidden;
          transform: translateX(-50%) translateY(10px);
          transition:
            opacity 0.3s ease 0s,
            visibility 0s linear 0.3s,
            transform 0.3s ease 0s;
        }
      }

      // Icona (container delle 3 linee)
      .header__menu-icon {
        position: relative;
        display: flex;
        flex-direction: column;
        justify-content: space-between;
        width: 70px;
        height: 52px;
        transition: width 0.5s ease 0s;
      }

      // Stato attivo
      &.is-active {
        .header__menu-label-text--menu {
          opacity: 0;
          visibility: hidden;
          transform: translateX(-50%) translateY(-10px);
          transition:
            opacity 0.3s ease 0s,
            visibility 0s linear 0.3s,
            transform 0.3s ease 0s;
        }
        .header__menu-label-text--close {
          opacity: 1;
          visibility: visible;
          transform: translateX(-50%) translateY(0);
          transition:
            opacity 0.3s ease 0.15s,
            visibility 0s linear 0.15s,
            transform 0.3s ease 0.15s;
        }

        .header__menu-icon {
          width: min(18.45vw, 280px);
          transition: width 0.5s ease 0.5s;
        }

        .header__menu-line {
          &:nth-child(1) {
            transform: translateY(17px);
            opacity: 0;
            transition:
              transform 0.3s ease 0s,
              opacity 0.2s ease 0.25s;
          }
          &:nth-child(2) {
            transform: none;
            transition: transform 0.3s ease 0s;
          }
          &:nth-child(3) {
            transform: translateY(-17px);
            opacity: 0;
            transition:
              transform 0.3s ease 0s,
              opacity 0.2s ease 0.25s;
          }
        }
      }
    }

    // ── VERSIONE DESKTOP (Flex style originale - solo da 769px in poi) ──
    &--desktop {
      display: none; // Nascosto di default

      @media (min-width: 769px) {
        display: flex;
        flex-direction: row;
        align-items: flex-start;
        padding-right: 80px;
      }

      // Label container
      .header__menu-label {
        position: relative;
        width: 1.2em;
        height: 4em;
        flex-shrink: 0;
      }

      // Testo MENU / CHIUDI (verticale)
      .header__menu-label-text {
        position: absolute;
        top: 0.9rem;
        left: -10px;
        font-size: $font-size-xs;
        font-weight: $font-weight-medium;
        letter-spacing: 0.1em;
        writing-mode: vertical-rl;
        transform: rotate(180deg);
        white-space: nowrap;

        &--menu {
          opacity: 1;
          visibility: visible;
          transition:
            opacity 0.3s ease 0.15s,
            visibility 0s linear 0.15s,
            transform 0.3s ease 0.15s;
        }

        &--close {
          opacity: 0;
          visibility: hidden;
          transform: rotate(180deg) translateX(20px);
          transition:
            opacity 0.3s ease 0s,
            visibility 0s linear 0.3s,
            transform 0.3s ease 0s;
        }
      }

      // Icona (container delle 3 linee)
      .header__menu-icon {
        position: absolute;
        left: 1.2em;
        top: 0;
        display: block;
        width: 80px;
        transition: width 0.5s ease 0s;
      }

      // Stato attivo
      &.is-active {
        .header__menu-label-text--menu {
          opacity: 0;
          visibility: hidden;
          transform: rotate(180deg) translateX(20px);
          transition:
            opacity 0.3s ease 0s,
            visibility 0s linear 0.3s,
            transform 0.3s ease 0s;
        }
        .header__menu-label-text--close {
          opacity: 1;
          visibility: visible;
          transform: rotate(180deg) translateX(0);
          transition:
            opacity 0.3s ease 0.15s,
            visibility 0s linear 0.15s,
            transform 0.3s ease 0.15s;
        }

        .header__menu-icon {
          width: min(18.45vw, 280px);
          transition: width 0.5s ease 0.5s;
        }

        .header__menu-line {
          &:nth-child(1) {
            transform: translateY(17px);
            opacity: 0;
            transition:
              transform 0.3s ease 0s,
              opacity 0.2s ease 0.25s;
          }
          &:nth-child(2) {
            transform: none;
            transition: transform 0.3s ease 0s;
          }
          &:nth-child(3) {
            transform: translateY(-17px);
            opacity: 0;
            transition:
              transform 0.3s ease 0s,
              opacity 0.2s ease 0.25s;
          }
        }
      }
    }
  }

  // ── Singola linea (comune a entrambe le versioni) ──
  &__menu-line {
    display: block;
    width: 100%;
    height: 1px;
    background: $color-dark;
    margin: 17px 0;
    position: relative;
    opacity: 1;
    // CHIUSURA: opacity torna a 1 leggermente prima, poi le linee si separano (delay 0.5s)
    transition:
      transform 0.3s ease 0.5s,
      opacity 0.2s ease 0.4s;
  }
}

// Logo
.logo {
  display: flex;
  align-items: flex-start;
  gap: $spacing-md;

  &__circle {
    width: 16px;
    height: 16px;
    border: 2px solid;
    border-radius: 50%;
    border-bottom-color: transparent !important;
  }

  &__text {
    font-size: $font-size-sm;
    font-weight: $font-weight-bold;
    letter-spacing: 0.15em;
    line-height: 1.3;
  }
}

.menu-overlay {
  position: fixed;
  inset: 0;
  z-index: $z-menu;
  pointer-events: none;
  visibility: hidden;

  // ── Stato attivo ──
  &.is-active {
    pointer-events: none;
    visibility: visible;

    // Blur backdrop: riceve i pointer-events
    .menu-overlay__blur-backdrop {
      opacity: 1;
      pointer-events: auto;
      z-index: 1;
    }

    // Reveal sinistro: perde i pointer-events
    .menu-overlay__reveal {
      transform: scaleX(1);
      pointer-events: none;
      background: transparent;
    }

    // Pannello destro: scaleX da 0 a 1 (da destra)
    .menu-overlay__panel {
      transform: scaleX(1);
      pointer-events: auto;
      z-index: 3;
    }

    // Linea header
    .menu-overlay__line {
      transform: scaleX(1);
    }

    // Sottotitolo
    .menu-overlay__subtitle {
      opacity: 1;
      transform: translateY(0);
      position: relative;
      top: -0.5rem;
    }

    // Items: appaiono in stagger (delay calcolato inline dallo :style)
    .menu-overlay__item {
      opacity: 1;
      transform: translateY(0);
    }
  }

  // ── Stato chiusura (delay invertiti) ──
  &.is-closing {
    visibility: visible;

    .menu-overlay__blur-backdrop {
      transition-delay: 1.1s; // Scompare quando il pannello ha finito di chiudersi (0.3s + 0.8s)
    }

    .menu-overlay__reveal {
      transition-delay: 0.4s;
    }

    .menu-overlay__panel {
      transition-delay: 0.3s;
      transform-origin: left center; // Si chiude verso sinistra
      transition-duration: 0.8s; // Più tempo per contrarsi completamente
      transition-timing-function: ease-in-out; // Lento-accelera-lento per smooth ending
    }

    .menu-overlay__line {
      transition-delay: 0s;
    }

    .menu-overlay__subtitle {
      transition-delay: 0s;
    }
  }

  // ── Reveal sinistro (sfondo grigio) ──
  &__reveal {
    position: fixed;
    top: 0;
    left: 0;
    width: 40%;
    height: 100vh;
    background: transparent;
    transform: scaleX(0);
    transform-origin: left center;
    // APERTURA: si espande con delay 0.1s | CHIUSURA: si chiude con delay 0.4s
    transition: transform 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94) 0.1s;
    z-index: 1;
    cursor: pointer;
    pointer-events: auto;

    @media (max-width: $breakpoint-lg) {
      display: none;
    }
  }

  // ── Blur backdrop (SOPRA il reveal, con z-index > reveal) ──
  &__blur-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%; // Blur su tutta la pagina
    height: 100vh;
    backdrop-filter: blur(8px);
    opacity: 0;
    // APERTURA: appare con delay 0.1s | CHIUSURA: scompare con delay 0.5s
    transition: opacity 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94) 0.1s;
    pointer-events: none;
    cursor: pointer;

    @media (max-width: $breakpoint-lg) {
      display: none;
    }
  }

  // ── Pannello destro (contenuto menu) ──
  &__panel {
    position: fixed;
    top: 0;
    right: 0;
    width: 62%;
    height: 100vh;
    background: $color-white;
    transform: scaleX(0);
    transform-origin: right center;
    // APERTURA: lento-accelera-lento per movimento smooth
    transition: transform 0.6s ease-in-out 0.2s;
    z-index: 2;
    display: flex;
    flex-direction: column;
    padding: $spacing-3xl;
    overflow-y: auto;
    pointer-events: none;

    @media (max-width: $breakpoint-lg) {
      width: 100%;
    }
  }

  // ── Header con linea + sottotitolo ──
  &__header {
    display: flex;
    gap: $spacing-lg;
    margin-bottom: $spacing-3xl;
    position: relative;
    margin-left: 5rem;
    top: -0.3rem;

    @media (max-width: $breakpoint-md) {
      display: none;
    }
  }

  &__line {
    width: 60px;
    height: 1px;
    background: $color-dark;
    transform: scaleX(0);
    transform-origin: left center;
    // APERTURA: appare con delay 0.6s | CHIUSURA: scompare con delay 0s
    transition: transform 0.5s ease 0.6s;
  }

  &__subtitle {
    font-size: $font-size-xs;
    letter-spacing: 0.1em;
    color: $color-text-light;
    opacity: 0;
    transform: translateY(-5px);
    // APERTURA: appare con delay 0.65s | CHIUSURA: scompare con delay 0s
    transition:
      opacity 0.4s ease 0.65s,
      transform 0.4s ease 0.65s;
  }

  // ── Lista menu ──
  &__list {
    flex: 1;
    display: flex;
    flex-direction: column;
    justify-content: center;
    gap: $spacing-sm;
  }

  &__item {
    overflow: hidden;
    opacity: 0;
    transform: translateY(20px);
    // CHIUSURA: gli items scompaiono (delay calcolato inline dallo :style)
    transition:
      opacity 0.35s ease,
      transform 0.35s ease;
  }

  &__link {
    display: inline-flex;
    align-items: center;
    gap: $spacing-md;
    font-size: clamp(2rem, 5vw, 3.5rem);
    font-weight: $font-weight-light;
    transition: color $transition-base;
    pointer-events: auto;

    &:hover {
      color: rgba(255, 196, 0, 0.8);
    }

    &.is-featured {
      color: $color-blue;
    }
  }

  &__icon {
    width: 40px;
    height: 40px;
  }
}

// MEDIA QUERIES
@media (min-width: $breakpoint-sm) {
  .header {
    width: 100%;

    &.is-visible {
      .header__logo .logo {
        width: 45%;
      }
    }

    &.is-scrolled {
      .header__logo .logo {
        width: 40%;
      }
    }
  }
}

@media (min-width: $breakpoint-md) {
  .header {
    width: calc(100% - 40px);

    &__container {
      display: flex;
    }

    &.is-scrolled {
      padding: 1.5rem $spacing-xl;
    }

    &.is-visible {
      .header__logo {
        width: 100%;

        .logo {
          width: 50%;
          padding-left: 0rem;
        }
      }

      .header__menu-btn {
        width: 15%;
      }
    }
  }
}

@media (min-width: $breakpoint-lg) {
  .header {
    width: calc(47% - 40px);

    &__container {
      width: 100%;
    }

    &.is-visible {
      .header__logo {
        width: 100%;

        .logo {
          width: 80%;
        }
      }
    }

    // Solo per versione desktop
    &__menu-btn--desktop {
      .header__menu-icon {
        width: 70px;
      }
    }
  }

  .menu-overlay__header {
    top: -0.8rem;
  }
}

@media (min-width: $breakpoint-xl) {
  .header {
    width: calc(41% - 40px);

    // Solo per versione desktop
    &__menu-btn--desktop {
